CREATE TRIGGER entities_ad AFTER DELETE ON entities BEGIN
      DELETE FROM entities_fts WHERE rowid = old.id;
    END

CREATE TRIGGER entities_au AFTER UPDATE ON entities BEGIN
      DELETE FROM entities_fts WHERE rowid = old.id;
      INSERT INTO entities_fts(rowid, entity_id, friendly_name, area_name, device_name)
      VALUES (new.id, new.entity_id, new.friendly_name, new.area_name, new.device_name);
    END

CREATE TRIGGER items_au AFTER UPDATE ON items BEGIN
    INSERT INTO items_fts(items_fts, rowid, name, marke, beschreibung, kategorie, unterkategorie, farbe, material)
    VALUES ('delete', old.id, old.name, old.marke, old.beschreibung, old.kategorie, old.unterkategorie, old.farbe, old.material);
    INSERT INTO items_fts(rowid, name, marke, beschreibung, kategorie, unterkategorie, farbe, material)
    VALUES (new.id, new.name, new.marke, new.beschreibung, new.kategorie, new.unterkategorie, new.farbe, new.material);
END
